old_generate = '''    def generate(self, person: dict, city: str, market_context: str) -> dict:\n        first_name = person.get("firstName") or "there"\n        prompt = f"""\n        You are writing as a helpful real estate team member at {self.rules.company_name}.\n        Draft a re-engagement email for a buyer lead.\n\n        Lead first name: {first_name}\n        City or area of interest: {city}\n        Market context: {market_context or 'Use general but non-fabricated language; do not invent statistics.'}\n\n        Requirements:\n        - Be useful and specific, not pushy.\n        - Do not invent exact market numbers unless provided in the market context.\n        - Ask one simple question to restart the conversation.\n        - Email must include a subject and body.\n        - Return strict JSON with keys: subject, email_body.\n        """\n'''
